// GitHub Release webhook -> draft changelog entry for QC Manager.
// Handles application/json and form-encoded (payload=...) GitHub webhooks.
let body = $json.body;
if (body && typeof body.payload === 'string') {
  try { body = JSON.parse(body.payload); } catch (e) {}
}

// Only act when a release is actually *published*. GitHub also fires
// created / edited / released / prereleased / deleted on the same event —
// acting on those would create duplicate entries.
if (!body || body.action !== 'published' || !body.release) {
  return [];
}

const release = body.release;
if (release.draft === true) {
  return [];
}

const tag = String(release.tag_name || '').slice(0, 50);
const title = String(release.name || release.tag_name || 'Release').slice(0, 255);

// Lightly clean GitHub's auto-generated notes: drop the trailing
// "**Full Changelog**: <url>" line; keep everything else as Markdown.
let md = String(release.body || '')
  .split('\n')
  .filter(line => !/^\s*\*\*Full Changelog\*\*:/i.test(line))
  .join('\n')
  .trim();

if (!md) md = 'Release ' + title + '.';

// QC API caps content_markdown at 20000 chars.
if (md.length > 20000) md = md.slice(0, 19980).trim() + '\n\n...';

return [{
  json: {
    version_number: tag || null,
    title: title,
    content_markdown: md,
    is_published: false,
    generated_by_ai: false,
    source: 'github',
    source_reference: 'github-release-' + (release.id != null ? release.id : tag),
  },
}];

// DISABLED by default. Enable this together with the "AI Summarize" node
// once you have added an ANTHROPIC_API_KEY env var to n8n.
// Reads the Anthropic Messages API response from the previous node and merges
// the generated text back with the changelog fields from "Build changelog".
const base = $('Build changelog').item.json;
let text = '';
try {
  text = ($json.content || [])
    .filter(b => b && b.type === 'text')
    .map(b => b.text)
    .join('\n')
    .trim();
} catch (e) { text = ''; }

let md = (text || base.content_markdown || '').trim();
if (md.length > 20000) md = md.slice(0, 19980).trim() + '\n\n...';

return [{ json: Object.assign({}, base, { content_markdown: md, generated_by_ai: true }) }];
